## 5. 数据库插件

```typescript
// src/plugins/database.ts





export default definePlugin({
  name: "database",
  async setup(app) {
    const dbConfig = (app.config as any).database ?? {
      url: "./data/app.db",
      wal: true,
      autoCreate: true,
    };

    app.logger.info({ url: dbConfig.url }, "正在连接数据库...");

    const { db, client } = createDatabase(dbConfig);

    // 挂载到 app
    app.extend("db", db);

    // 就绪钩子：验证连接 + 填充种子数据
    app.onReady(async () => {
      try {
        // 验证连接
        client.pragma("quick_check");
        app.logger.info("数据库连接验证成功");

        // 检查是否需要种子数据
        const userCount = db.select().from(users).all();
        if (userCount.length === 0) {
          app.logger.info("数据库为空，正在填充种子数据...");
          await seedDatabase(db);
          app.logger.info("种子数据填充完成");
        }
      } catch (err) {
        app.logger.error({ error: err }, "数据库初始化失败");
        throw err;
      }
    });

    // 关闭钩子：断开连接
    app.onClose(() => {
      client.close();
      app.logger.info("数据库连接已关闭");
    });
  },
});

/**
 * 填充种子数据（仅在数据库为空时执行）
 */
async function seedDatabase(db: DrizzleDB): Promise<void> {
  // 插入用户
  const insertedUsers = db
    .insert(users)
    .values([
      {
        name: "Alice",
        email: "alice@example.com",
        age: 28,
        role: "admin",
        bio: "全栈开发者，热爱开源",
      },
      {
        name: "Bob",
        email: "bob@example.com",
        age: 32,
        role: "user",
        bio: "前端工程师",
      },
      {
        name: "Charlie",
        email: "charlie@example.com",
        age: 25,
        role: "editor",
        bio: "技术博客作者",
      },
    ])
    .returning()
    .all();

  // 插入文章
  db.insert(posts)
    .values([
      {
        title: "VextJS 入门指南",
        content: "本文介绍如何使用 VextJS 构建高性能 RESTful API...",
        authorId: insertedUsers[0].id,
        published: true,
      },
      {
        title: "Drizzle ORM 最佳实践",
        content: "探索 Drizzle ORM 的高级查询技巧...",
        authorId: insertedUsers[0].id,
        published: true,
      },
      {
        title: "TypeScript 类型体操",
        content: "深入理解 TypeScript 的高级类型系统...",
        authorId: insertedUsers[2].id,
        published: false,
      },
    ])
    .run();
}
```

为 `app.db` 添加类型声明：

```typescript
// types/vext.d.ts


declare module "vextjs" {
  interface VextApp {
    db: DrizzleDB;
  }

  interface VextConfig {
    database?: {
      url: string;
      wal?: boolean;
      autoCreate?: boolean;
    };
  }

  interface VextRequest {
    user?: {
      id: string;
      role: string;
    };
  }
}
```

